from airflow.models import BaseOperator
from airflow.utils.context import Context

class BronzeIngestionOperator(BaseOperator):
    def execute(self, context: Context) -> dict:
        ti = context['ti']

        # Push download metadata under a specific key
        ti.xcom_push(
            key='download_metadata',
            value={'file_size': 1024000, 'duration_seconds': 12.3}
        )

        # Push validation result under a different key
        ti.xcom_push(
            key='validation_result',
            value={'valid_rows': 1180000, 'rejected_rows': 20000,
                   'rejection_details': [...]}  # Could be large
        )

        # Return value goes under the default 'return_value' key
        return {'status': 'success', 'total_rows': 1200000}

# Downstream task pulls only the key it needs
@task
def monitor_downloads(**context):
    ti = context['ti']
    # Pulls only the small download_metadata, not the large validation_result
