@dag(
    dag_id='dag_sla_monitor',
    schedule='*/30 * * * *',  # Every 30 minutes
    start_date=datetime(2026, 1, 1),
    catchup=False,
    tags=['monitoring', 'sla', 'saulegrid'],
)
def dag_sla_monitor():

    @task
    def check_sla_progress():
        """Check whether today's DAG runs are on track to meet SLAs."""
        today = now('Europe/Vilnius').start_of('day')
        alerts = []

        for dag_id, max_hours in SLA_THRESHOLDS.items():
            deadline = today.add(hours=max_hours)
            current_time = now('Europe/Vilnius')

            # Check if the DAG Run exists and its status
            dag_run = DagRun.find(
                dag_id=dag_id,
                execution_date=today,
            )

            if not dag_run:
                if current_time > today.add(hours=max_hours * 0.5):
                    alerts.append({
                        'dag_id': dag_id,
                        'issue': 'No DAG Run created',
                        'deadline': str(deadline),
                        'severity': 'warning',
                    })
            elif dag_run[0].state == 'failed':
                alerts.append({
                    'dag_id': dag_id,
                    'issue': 'DAG Run failed',
                    'deadline': str(deadline),
                    'severity': 'critical',
                })

        if alerts:
            send_sla_alerts(alerts)
        return {'alerts': len(alerts), 'checked': len(SLA_THRESHOLDS)}

    check_sla_progress()

