@task
def transform_meters_with_dead_letter(data_date: str) -> dict:
    """Transform meter readings with dead-letter routing for rejected records."""
    raw_data = read_bronze_meters(data_date)

    valid_records = []
    dead_letters = []

    for record in raw_data:
        rejection = validate_meter_record(record)

        if rejection is None:
            valid_records.append(record)
        else:
            dead_letters.append({
                'original_record': record,
                'rejection_reason': rejection['reason'],
                'rejection_code': rejection['code'],
                'pipeline_stage': 'silver_transform',
                'data_date': data_date,
                'rejected_at': datetime.utcnow().isoformat(),
                'source_dag': 'dag_silver_meters',
            })

    # Write valid records to Silver (delete-then-write for idempotency)
    write_silver_meters(valid_records, data_date)

    # Write dead letters to the dead-letter table (upsert on record key + date)
    if dead_letters:
        write_dead_letters(dead_letters, table='dead_letter.meters')

    return {
        'valid_rows': len(valid_records),
        'rejected_rows': len(dead_letters),
        'rejection_rate': len(dead_letters) / len(raw_data) * 100,
        'data_date': data_date,
    }

def validate_meter_record(record: dict) -> dict | None:
    """Validate a single meter record.

    Returns None if valid, or a rejection dict if invalid.
    Each check has a unique code for automated categorization.
    """
    # Check 1: meter_id must not be null
    if not record.get('meter_id'):
        return {
            'reason': f'Null meter_id in record for date {record.get("date")}',
            'code': 'NULL_METER_ID',
        }

    # Check 2: daily_kw must not be negative (except prosumer generation)
    if record.get('daily_kw', 0) < 0 and record.get('customer_type') != 'PROSUMER':
        return {
            'reason': f'Negative daily_kw ({record["daily_kw"]}) for '
                      f'non-prosumer meter {record["meter_id"]}',
            'code': 'NEGATIVE_KW_NON_PROSUMER',
        }

    # Check 3: date must not be in the future
    from datetime import date
    if record.get('date') and record['date'] > date.today().isoformat():
        return {
            'reason': f'Future date {record["date"]} for meter {record["meter_id"]}',
            'code': 'FUTURE_DATE',
        }

    # Check 4: region must be a known SaulėGrid region
    valid_regions = {
        'VILNIUS', 'KAUNAS', 'KLAIPEDA', 'SIAULIAI', 'PANEVEZYS',
        'ALYTUS', 'MARIJAMPOLE', 'UTENA', 'TELSIAI', 'TAURAGE'
    }
    if record.get('region') not in valid_regions:
        return {
            'reason': f'Unknown region "{record.get("region")}" '
                      f'for meter {record["meter_id"]}',
            'code': 'UNKNOWN_REGION',
        }

    return None  # All checks passed

