from airflow.decorators import task

@task
def check_cross_dag_consistency() -> dict:
    """Verify that Bronze, Silver, and Gold are consistent.

    Checks that the latest data date in each layer matches.
    Fires alerts when layers are out of sync.
    """
    bronze_latest = get_latest_date('bronze', 'meters')
    silver_latest = get_latest_date('silver', 'meters')
    gold_latest = get_latest_date('gold', 'billing')

    inconsistencies = []

    if silver_latest < bronze_latest:
        inconsistencies.append({
            'gap': 'Bronze → Silver',
            'bronze_date': str(bronze_latest),
            'silver_date': str(silver_latest),
            'days_behind': (bronze_latest - silver_latest).days,
        })

    if gold_latest < silver_latest:
        inconsistencies.append({
            'gap': 'Silver → Gold',
            'silver_date': str(silver_latest),
            'gold_date': str(gold_latest),
            'days_behind': (silver_latest - gold_latest).days,
        })

    if inconsistencies:
        severity = 'critical' if any(
            i['days_behind'] > 1 for i in inconsistencies
        ) else 'warning'
        send_alert(
            channel='#saulegrid-alerts',
            message=f'Cross-DAG inconsistency detected: {inconsistencies}',
            severity=severity,
        )

    return {
        'bronze_latest': str(bronze_latest),
        'silver_latest': str(silver_latest),
        'gold_latest': str(gold_latest),
        'consistent': len(inconsistencies) == 0,
        'inconsistencies': inconsistencies,
    }

