    """Every production DAG must have at least one tag."""
    dag = dag_bag.dags[dag_id]
    assert dag.tags, f'{dag_id} has no tags. Tags are required for UI filtering.'


@pytest.mark.parametrize('dag_id', [
    'dag_gold_billing', 'dag_gold_forecast',
])
