    """Gold DAGs must have SLA callbacks configured."""
    dag = dag_bag.dags[dag_id]
    assert dag.sla_miss_callback is not None, (
        f'{dag_id} has no sla_miss_callback. '
        f'Gold DAGs require SLA monitoring (Module 3, lesson 5).'
    )

def test_bronze_meters_task_structure(dag_bag):
    """Verify dag_bronze_meters has the expected tasks and dependencies."""
    dag = dag_bag.dags['dag_bronze_meters']
    task_ids = {task.task_id for task in dag.tasks}

    # Required tasks must exist
    required_tasks = {'ingest_meters'}
    missing = required_tasks - task_ids
    assert not missing, f'Missing required tasks: {missing}'

    # Verify the ingestion task has outlets (Dataset scheduling)
    ingest_task = dag.get_task('ingest_meters')
