    """Bronze tasks that access external systems must have retries configured."""
    bronze_dags = [
        dag_id for dag_id in dag_bag.dags 
        if dag_id.startswith('dag_bronze_')
    ]

    for dag_id in bronze_dags:
        dag = dag_bag.dags[dag_id]
        for task in dag.tasks:
