# scripts/check_deprecated.py — run in CI to catch deprecated API usage
import ast
import sys
from pathlib import Path

# Deprecated patterns for Airflow 2.8+
DEPRECATED_PATTERNS = {
    'schedule_interval': 'Use schedule= instead of schedule_interval= (deprecated in 2.4)',
    'execution_date': 'Use logical_date or data_interval_start instead (deprecated in 2.4)',
    'provide_context': 'Remove provide_context=True — context is always provided in 2.0+',
    'SubDagOperator': 'Use TaskGroup instead of SubDagOperator (deprecated in 2.0)',
}

def check_file(filepath: Path) -> list[str]:
    """Scan a Python file for deprecated Airflow patterns."""
    violations = []
    source = filepath.read_text()

    for pattern, message in DEPRECATED_PATTERNS.items():
        if pattern in source:
            # Find the line number
            for i, line in enumerate(source.splitlines(), 1):
                if pattern in line:
                    violations.append(
                        f'{filepath}:{i}: {pattern} — {message}'
                    )
    return violations

def main():
    dag_dir = Path('dags/')
    all_violations = []

    for filepath in dag_dir.glob('*.py'):
        all_violations.extend(check_file(filepath))

    if all_violations:
        print('Deprecated API usage detected:')
        for v in all_violations:
            print(f'  {v}')
        sys.exit(1)
    else:
        print('No deprecated API usage found.')

if __name__ == '__main__':
    main()

