import pytest
from airflow.models import DagBag
from saulegrid_common.datasets import (
    bronze_meters, bronze_generation, bronze_weather,
    silver_meters, silver_generation,
)

KNOWN_DATASETS = {
    str(bronze_meters.uri), str(bronze_generation.uri),
    str(bronze_weather.uri), str(silver_meters.uri),
    str(silver_generation.uri),
}

@pytest.fixture(scope='session')
def dag_bag():
    return DagBag(dag_folder='dags/', include_examples=False)


def test_dataset_scheduled_dags_no_catchup(dag_bag):
    """Dataset-scheduled DAGs must have catchup=False."""
    for dag_id, dag in dag_bag.dags.items():
        if hasattr(dag.timetable, 'dataset_condition'):
            assert not dag.catchup, (
                f'{dag_id}: Dataset-scheduled DAG has catchup=True. '
                f'This creates backfill runs for every historical Dataset update. '
                f'Set catchup=False.'
            )


def test_no_sensor_cron_overlap(dag_bag):
    """DAGs should not use both cron scheduling and ExternalTaskSensors."""
    from airflow.sensors.external_task import ExternalTaskSensor

    for dag_id, dag in dag_bag.dags.items():
        has_cron = hasattr(dag.timetable, 'periodic') and dag.timetable.periodic
        has_sensor = any(
            isinstance(task, ExternalTaskSensor) for task in dag.tasks
        )
        if has_cron and has_sensor:
            pytest.fail(
                f'{dag_id}: Uses both cron scheduling and ExternalTaskSensor. '
                f'Migrate to Dataset scheduling (Module 1) to eliminate sensors.'
            )

