# Querying the audit log programmatically
# Used by SaulėGrid's security monitoring DAG

from airflow.decorators import task
from airflow.utils.session import provide_session
from airflow.models import Log
from datetime import datetime, timedelta

@task
@provide_session
def check_sensitive_actions(session=None) -> dict:
    """Check for sensitive actions in the last 24 hours."""
    since = datetime.utcnow() - timedelta(hours=24)

    sensitive_events = [
        'dag.pause', 'dag.unpause',
        'connection.create', 'connection.edit', 'connection.delete',
        'variable.create', 'variable.edit', 'variable.delete',
        'role.create', 'role.edit',
    ]

    logs = session.query(Log).filter(
        Log.dttm >= since,
        Log.event.in_(sensitive_events),
    ).all()

    alerts = []
    for log_entry in logs:
        # Flag actions by non-engineer roles
        if log_entry.owner not in ('matas.engineer', 'ieva.engineer', 'jonas.engineer'):
            alerts.append({
                'event': log_entry.event,
                'user': log_entry.owner,
                'resource': log_entry.extra,
                'timestamp': str(log_entry.dttm),
            })

    if alerts:
        send_security_alert(
            message=f'{len(alerts)} sensitive actions by non-engineer users',
            details=alerts,
        )

    return {'total_events': len(logs), 'alerts': len(alerts)}

