# Measuring scheduling delay from the Airflow metadata
from airflow.decorators import task
from airflow.utils.session import provide_session
from airflow.models import TaskInstance
from datetime import datetime, timedelta

@task
@provide_session
def measure_scheduling_delay(session=None) -> dict:
    """Measure the average scheduling delay for recent task instances."""
    since = datetime.utcnow() - timedelta(hours=24)

    tis = session.query(TaskInstance).filter(
        TaskInstance.start_date >= since,
        TaskInstance.state == 'success',
    ).all()

    delays = []
    for ti in tis:
        if ti.queued_dttm and ti.start_date:
            # Time from queued to actually running
            delay = (ti.start_date - ti.queued_dttm).total_seconds()
            delays.append(delay)

    if delays:
        avg_delay = sum(delays) / len(delays)
        p95_delay = sorted(delays)[int(len(delays) * 0.95)]
    else:
        avg_delay = p95_delay = 0

    return {
        'task_count': len(delays),
        'avg_scheduling_delay_sec': round(avg_delay, 1),
        'p95_scheduling_delay_sec': round(p95_delay, 1),
    }

